class Solution:
    def infixToPostfix(self, s: str) -> str:
        precedence = {'+': 1, '-': 1, '*': 2, '/': 2, '^': 3}
        stack = []
        postfix = ''

        for char in s:
            if char.isalnum():
                postfix += char
            elif char == '(':
                stack.append(char)
            elif char == ')':
                while stack and stack[-1] != '(':
                    postfix += stack.pop()
                if stack and stack[-1] == '(':
                    stack.pop()
            else:
                while stack and stack[-1] != '(' and precedence.get(char, 0) <= precedence.get(stack[-1], 0):
                    postfix += stack.pop()
                stack.append(char)

        while stack:
            postfix += stack.pop()

        return postfix

