#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string infixToPostfix(string s) {
        unordered_map<char, int> precedence = {{'+', 1}, {'-', 1}, {'*', 2}, {'/', 2}, {'^', 3}};
        stack<char> stack;
        string postfix;

        for (char c : s) {
            if (isalnum(c)) {
                postfix += c;
            } else if (c == '(') {
                stack.push(c);
            } else if (c == ')') {
                while (!stack.empty() && stack.top() != '(') {
                    postfix += stack.top();
                    stack.pop();
                }
                if (!stack.empty() && stack.top() == '(') {
                    stack.pop();
                }
            } else {
                while (!stack.empty() && stack.top() != '(' && precedence.count(c) && precedence[c] <= precedence[stack.top()]) {
                    postfix += stack.top();
                    stack.pop();
                }
                stack.push(c);
            }
        }

        while (!stack.empty()) {
            postfix += stack.top();
            stack.pop();
        }

        return postfix;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    if (!(cin >> s)) return 0;
    Solution sol;
    string ans = sol.infixToPostfix(s);
    cout << ans << endl;
    return 0;
}
